const familia = $input.first().json;
const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const mes = meses[new Date().getMonth()];
const anio = new Date().getFullYear();

// CAMBIAR ESTE ENLACE por el de tu Google Form real
const enlaceEncuesta = 'https://forms.gle/XXXXXXXXXXXXXXXX';

const cuerpo = `Estimada familia ${familia.nombre_familia},\n\n`
  + `Desde el centro queremos conocer su opinion sobre el funcionamiento del curso ${familia.curso} durante el mes de ${mes}.\n\n`
  + `Le agradeceriamos que dedicara 2 minutos a completar esta breve encuesta de satisfaccion:\n\n`
  + `${enlaceEncuesta}\n\n`
  + `Sus respuestas son anonimas y nos ayudan a mejorar.\n\n`
  + `Gracias por su colaboracion,\n`
  + `Equipo directivo`;

return [{ json: {
  email: familia.email,
  asunto: `Encuesta de satisfaccion - ${mes} ${anio} (${familia.curso})`,
  cuerpo,
  nombre_familia: familia.nombre_familia,
  curso: familia.curso
}}];
